import React, { createContext, useState, useEffect, useContext } from 'react';

const ThemeContext = createContext({
    isDarkMode: false,
    toggleTheme: () => { }
});

export const useTheme = () => useContext(ThemeContext);

export const ThemeProvider = ({ children }) => {
    // Initialize state correctly for server-side rendering support
    const [isDarkMode, setIsDarkMode] = useState(false);
    const [hasMounted, setHasMounted] = useState(false);

    // Correctly initialize state for SSR (default to false/light)
    // We do NOT use hasMounted to block rendering, otherwise context is missing during SSR

    useEffect(() => {
        setHasMounted(true);
        // Check localStorage or system preference
        const savedTheme = localStorage.getItem('theme');
        const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;

        if (savedTheme === 'dark' || (!savedTheme && prefersDark)) {
            setIsDarkMode(true);
            document.body.classList.add('dark-mode');
        } else {
            setIsDarkMode(false);
            document.body.classList.remove('dark-mode');
        }
    }, []);

    const toggleTheme = () => {
        if (isDarkMode) {
            document.body.classList.remove('dark-mode');
            localStorage.setItem('theme', 'light');
            setIsDarkMode(false);
        } else {
            document.body.classList.add('dark-mode');
            localStorage.setItem('theme', 'dark');
            setIsDarkMode(true);
        }
    };

    return (
        <ThemeContext.Provider value={{ isDarkMode, toggleTheme }}>
            {children}
        </ThemeContext.Provider>
    );
};
